Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAPRT" &CreDtaPrt.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
if &CreDtaVct_To.IsEmpty() and &CreDtaVct.IsEmpty() &CreDtaVct_To = serverdate() EndIF
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False &DynamicFiltersOperator1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False &DynamicFiltersOperator2.Visible = False &DynamicFiltersOperator3.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CRECLICOD' &CreCliCod1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCliRaz1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreDupNro1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 0);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CRECLICOD' &CreCliCod2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCliRaz2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreDupNro2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 0);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CRECLICOD' &CreCliCod3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCliRaz3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreDupNro3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"CREDTAVCT", "", not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()), 0, &CreDtaVct.ToString().Trim(), &CreDtaVct_To.ToString().Trim()) WWP_GridStateAddFilterValue(&GridState, !"CRERECPAG", "", true, 0, &CreRecPag, '') WWP_GridStateAddFilterValue(&GridState, !"CRESTS", "", not &CreSts.IsEmpty(), 0, &CreSts, '') WWP_GridStateAddFilterValue(&GridState, !"CREDTAPRT", "", not &CreDtaPrt.IsEmpty(), 0, &CreDtaPrt.ToString().Trim(), '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'CRECLICOD' AND not &CreCliCod1.IsEmpty() &GridStateDynamicFilter.Value = &CreCliCod1.ToString() Case &DynamicFiltersSelector1 = !'CRECLIRAZ' AND not &CreCliRaz1.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'CREDUPNRO' AND not &CreDupNro1.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'CRECBRNOM' AND not &CreCbrNom1.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'CRECLICOD' AND not &CreCliCod2.IsEmpty() &GridStateDynamicFilter.Value = &CreCliCod2.ToString() Case &DynamicFiltersSelector2 = !'CRECLIRAZ' AND not &CreCliRaz2.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'CREDUPNRO' AND not &CreDupNro2.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'CRECBRNOM' AND not &CreCbrNom2.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'CRECLICOD' AND not &CreCliCod3.IsEmpty() &GridStateDynamicFilter.Value = &CreCliCod3.ToString() Case &DynamicFiltersSelector3 = !'CRECLIRAZ' AND not &CreCliRaz3.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'CREDUPNRO' AND not &CreDupNro3.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'CRECBRNOM' AND not &CreCbrNom3.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
