&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"DuplicatasCompleto"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
