EndEvent
Sub 'GravaPadrao'
&PadObs = IIF(&IsProtestada = true,'1','0') &PadObs += STR(&CrePedCod) PadraoUsuario.Call('G', &Pgmname, &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
EndSub
Sub 'DuplicatasSelecionadas'
&SdtPagamentoDuplicata.Clear() // Zera Sdt For Each line If CreSts <> 'C' If &CreDupSel = True // Se estiver Marcada &SdtPagamentoDuplicataItem = new() &SdtPagamentoDuplicataItem.EmpCod = EmpCod &SdtPagamentoDuplicataItem.CreCod = CreCod &SdtPagamentoDuplicataItem.FilCod = FilCod &SdtPagamentoDuplicataItem.CreCliCod = CreCliCod &SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz &SdtPagamentoDuplicataItem.CreCliCidNom = CreCliCobCidNom &SdtPagamentoDuplicataItem.CreCliUfeCod = CreCliCobUfeCod &SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo &SdtPagamentoDuplicataItem.CreVlrPgt = CreVlrDup &SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod &SdtPagamentoDuplicataItem.CrePedCod = CrePedCod &SdtPagamentoDuplicataItem.CreDupNro = CreDupNro &SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms &SdtPagamentoDuplicataItem.CreDtaPrt = CreDtaPrt &SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc &sdtPagamentoDuplicataItem.MovCpl = 'CL:' + trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz) &SdtPagamentoDuplicataItem.CreSts = CreSts &SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem) EndIF EndIf EndFor If &SdtPagamentoDuplicata.count > 0 &WebSession.Set('AnuenciaDP',&SdtPagamentoDuplicata.ToXml())
WPDuplicataAnuenciaNovo.Call() Else msg('Atenção nenhuma duplicata selecionada!') EndIf
EndSub
